def threeSum(nums):
    nums = sorted(nums)
    output = []
    i = 0

    while i < len(nums) - 2 and nums[i] <= 0:
        
        k = len(nums) - 1
        j = i + 1

        while j < k:
            
            if nums[i] + nums[j] > 0:
                break

            total = nums[i] + nums[j] + nums[k]

            if total == 0:
                output.append([nums[i], nums[j], nums[k]])

                k -= 1
                j += 1

                while j < k and nums[k] == nums[k + 1]:
                    k -= 1

                while j < k and nums[j] == nums[j - 1]:
                    j += 1
            
            elif total < 0:
                j += 1

            elif total > 0:
                k -= 1

        i += 1

        while i < len(nums) - 2 and nums[i] == nums[i - 1]:
            i += 1
        
    return output





